-- ============================================================\n-- CUSTOMER PORTAL — Migration 09: Memberships & Wallet\n-- ============================================================\n\n-- Membership levels\nCREATE TABLE IF NOT EXISTS public.membership_levels (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  level_name TEXT NOT NULL UNIQUE CHECK (level_name IN ('Bronze','Silver','Gold','Platinum')),\n  min_spent_sar NUMERIC(15,2) NOT NULL DEFAULT 0,\n  discount_percentage NUMERIC(5,2) NOT NULL DEFAULT 0,\n  benefits TEXT[] DEFAULT '{}'::text[],\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Populate default membership levels\nINSERT INTO public.membership_levels (level_name, min_spent_sar, discount_percentage, benefits)\nVALUES \n  ('Bronze', 0.00, 0.00, ARRAY['Standard support', 'Regular checkout']),\n  ('Silver', 50000.00, 2.00, ARRAY['Priority support', '2% discount on all purchases', 'Monthly statements']),\n  ('Gold', 150000.00, 5.00, ARRAY['Dedicated account manager', '5% discount on all purchases', 'Free storage up to 5m3', 'Fast-track delivery']),\n  ('Platinum', 500000.00, 10.00, ARRAY['24/7 Premium support', '10% discount on all purchases', 'Free storage up to 20m3', 'Priority warehouse allocation', 'Custom payment terms'])\nON CONFLICT (level_name) DO UPDATE \nSET min_spent_sar = EXCLUDED.min_spent_sar, \n    discount_percentage = EXCLUDED.discount_percentage, \n    benefits = EXCLUDED.benefits;\n\n-- Customer memberships\nCREATE TABLE IF NOT EXISTS public.customer_memberships (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  customer_id BIGINT REFERENCES public.customer_profiles(id) ON DELETE CASCADE UNIQUE NOT NULL,\n  level_id BIGINT REFERENCES public.membership_levels(id) NOT NULL,\n  total_spent_sar NUMERIC(15,2) DEFAULT 0,\n  joined_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),\n  expires_at TIMESTAMP WITH TIME ZONE,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Customer wallets\nCREATE TABLE IF NOT EXISTS public.customer_wallets (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  customer_id BIGINT REFERENCES public.customer_profiles(id) ON DELETE CASCADE UNIQUE NOT NULL,\n  balance NUMERIC(15,2) NOT NULL DEFAULT 0.00 CHECK (balance >= 0),\n  currency TEXT DEFAULT 'SAR',\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Wallet transactions\nCREATE TABLE IF NOT EXISTS public.customer_wallet_transactions (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  wallet_id BIGINT REFERENCES public.customer_wallets(id) ON DELETE CASCADE NOT NULL,\n  amount NUMERIC(15,2) NOT NULL,\n  transaction_type TEXT NOT NULL CHECK (transaction_type IN ('Deposit','Payment','Refund','Bonus','StorageCharge')),\n  reference_id TEXT,\n  description TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Enable RLS\nALTER TABLE public.membership_levels ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_memberships ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_wallets ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_wallet_transactions ENABLE ROW LEVEL SECURITY;\n\n-- Policies\nCREATE POLICY IF NOT EXISTS \"Membership levels visible to everyone\"\n  ON public.membership_levels FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY IF NOT EXISTS \"Customers view their own membership\"\n  ON public.customer_memberships FOR SELECT\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_memberships.customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers view their own wallet\"\n  ON public.customer_wallets FOR SELECT\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_wallets.customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers view their own wallet transactions\"\n  ON public.customer_wallet_transactions FOR SELECT\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_wallets w\n    JOIN public.customer_profiles p ON p.id = w.customer_id\n    WHERE w.id = customer_wallet_transactions.wallet_id AND p.portal_user_id = auth.uid()\n  ));\n
